import React, { useState, useMemo } from "react";

const citiesPreset = [
  "Atlanta, US",
  "Athens, US",
  "New York, US",
  "Los Angeles, US",
  "Chicago, US",
  "Houston, US",
  "San Francisco, US",
  "Dallas, US",
  "Miami, US",
  "Seattle, US",
];

export default function SearchSection({ favorites = [], onSelectCity, onAddFavorite }) {
  const [query, setQuery] = useState("");
  const allOptions = useMemo(() => {
    const set = new Set([...
      favorites,
      ...citiesPreset
    ]);
    return Array.from(set);
  }, [favorites]);

  const filtered = useMemo(() => {
    if (!query) return allOptions.slice(0, 8);
    const q = query.toLowerCase();
    return allOptions.filter(c => c.toLowerCase().includes(q)).slice(0, 8);
  }, [query, allOptions]);

  return (
    <div className="relative">
      <div className="flex items-center gap-2 rounded-full pl-4 pr-2 py-2 shadow-lg border border-white/10 bg-white/20 dark:bg-white/10 backdrop-blur">
        <svg className="w-5 h-5 opacity-80" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
        <input
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search city…"
          className="flex-1 bg-transparent outline-none placeholder:opacity-60 text-sm"
        />
        <button
          onClick={() => {
            const c = query.trim();
            if (!c) return;
            onSelectCity && onSelectCity(c);
            onAddFavorite && onAddFavorite(c);
            setQuery("");
          }}
          className="text-xs px-3 py-1 rounded-full border border-white/20 bg-white/20 hover:bg-white/30"
        >Go</button>
      </div>

      {/* dropdown */}
      <div className="absolute left-0 right-0 mt-2 rounded-2xl overflow-hidden shadow-xl border border-white/10 bg-white/80 dark:bg-black/70 backdrop-blur">
        {filtered.length === 0 ? (
          <div className="px-4 py-3 text-sm opacity-70">No matches</div>
        ) : (
          filtered.map((c) => (
            <button
              key={c}
              onClick={() => onSelectCity && onSelectCity(c)}
              className="w-full text-left px-4 py-2 text-sm hover:bg-white/50 dark:hover:bg-white/10"
            >{c}</button>
          ))
        )}

        {favorites?.length > 0 && (
          <div className="border-t border-white/10">
            <div className="px-4 py-2 text-[11px] uppercase tracking-wide opacity-60">Favorites</div>
            {favorites.slice(0, 6).map((c) => (
              <button
                key={c+"fav"}
                onClick={() => onSelectCity && onSelectCity(c)}
                className="w-full text-left px-4 py-2 text-sm hover:bg-white/50 dark:hover:bg-white/10"
              >{c}</button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
